						.dD_OUT(i_rd_data_cdc_dD_OUT));

  // submodule i_wr_resp_cdc
  SyncFIFO1 #(.dataWidth(32'd4)) i_wr_resp_cdc(.sCLK(CLK_hb_clk),
					       .dCLK(CLK),
					       .sRST(RST_N_hb_rstn),
					       .sD_IN(i_wr_resp_cdc_sD_IN),
					       .sENQ(i_wr_resp_cdc_sENQ),
					       .dDEQ(i_wr_resp_cdc_dDEQ),
					       .sFULL_N(i_wr_resp_cdc_sFULL_N),
					       .dEMPTY_N(i_wr_resp_cdc_dEMPTY_N),
					       .dD_OUT(i_wr_resp_cdc_dD_OUT));

  // submodule o_rd_addr_cdc
  SyncFIFO1 #(.dataWidth(32'd63)) o_rd_addr_cdc(.sCLK(CLK),
						.dCLK(CLK_hb_clk),
						.sRST(RST_N),
						.sD_IN(o_rd_addr_cdc_sD_IN),
						.sENQ(o_rd_addr_cdc_sENQ),
						.dDEQ(o_rd_addr_cdc_dDEQ),
						.sFULL_N(o_rd_addr_cdc_sFULL_N),
						.dEMPTY_N(o_rd_addr_cdc_dEMPTY_N),
						.dD_OUT(o_rd_addr_cdc_dD_OUT));

  // submodule o_wr_addr_cdc
  SyncFIFO1 #(.dataWidth(32'd63)) o_wr_addr_cdc(.sCLK(CLK),
						.dCLK(CLK_hb_clk),
						.sRST(RST_N),
						.sD_IN(o_wr_addr_cdc_sD_IN),
						.sENQ(o_wr_addr_cdc_sENQ),
						.dDEQ(o_wr_addr_cdc_dDEQ),
						.sFULL_N(o_wr_addr_cdc_sFULL_N),
						.dEMPTY_N(o_wr_addr_cdc_dEMPTY_N),
						.dD_OUT(o_wr_addr_cdc_dD_OUT));

  // submodule o_wr_data_cdc
  SyncFIFO1 #(.dataWidth(32'd73)) o_wr_data_cdc(.sCLK(CLK),
						.dCLK(CLK_hb_clk),
						.sRST(RST_N),
						.sD_IN(o_wr_data_cdc_sD_IN),
						.sENQ(o_wr_data_cdc_sENQ),
						.dDEQ(o_wr_data_cdc_dDEQ),
						.sFULL_N(o_wr_data_cdc_sFULL_N),
						.dEMPTY_N(o_wr_data_cdc_dEMPTY_N),
						.dD_OUT(o_wr_data_cdc_dD_OUT));

  // submodule timeout_counter
  Counter #(.width(32'd10), .init(10'd1023)) timeout_counter(.CLK(CLK_hb_clk),
							     .RST(RST_N_hb_rstn),
							     .DATA_A(timeout_counter_DATA_A),
							     .DATA_B(timeout_counter_DATA_B),
							     .DATA_C(timeout_counter_DATA_C),
							     .DATA_F(timeout_counter_DATA_F),
							     .ADDA(timeout_counter_ADDA),
							     .ADDB(timeout_counter_ADDB),
							     .SETC(timeout_counter_SETC),
							     .SETF(timeout_counter_SETF),
							     .Q_OUT(timeout_counter_Q_OUT));

  // rule RL_cdc1
  assign CAN_FIRE_RL_cdc1 =
	     o_wr_addr_cdc_sFULL_N && axi_data_f_wr_addr_EMPTY_N ;
  assign WILL_FIRE_RL_cdc1 = CAN_FIRE_RL_cdc1 ;

  // rule RL_cdc2
  assign CAN_FIRE_RL_cdc2 =
	     o_wr_data_cdc_sFULL_N && axi_data_f_wr_data_EMPTY_N ;
  assign WILL_FIRE_RL_cdc2 = CAN_FIRE_RL_cdc2 ;

  // rule RL_cdc3
  assign CAN_FIRE_RL_cdc3 =
	     o_rd_addr_cdc_sFULL_N && axi_data_f_rd_addr_EMPTY_N ;
  assign WILL_FIRE_RL_cdc3 = CAN_FIRE_RL_cdc3 ;

  // rule RL_cdc4
  assign CAN_FIRE_RL_cdc4 =
	     i_wr_resp_cdc_dEMPTY_N && axi_data_f_wr_resp_FULL_N ;
  assign WILL_FIRE_RL_cdc4 = CAN_FIRE_RL_cdc4 ;

  // rule RL_cdc5
  assign CAN_FIRE_RL_cdc5 =
	     i_rd_data_cdc_dEMPTY_N && axi_data_f_rd_data_FULL_N ;
  assign WILL_FIRE_RL_cdc5 = CAN_FIRE_RL_cdc5 ;

  // rule RL_wr
  assign CAN_FIRE_RL_wr =
	     i_wr_resp_cdc_sFULL_N && o_wr_addr_cdc_dEMPTY_N &&
	     o_wr_data_cdc_dEMPTY_N &&
	     !reading ;
  assign WILL_FIRE_RL_wr = CAN_FIRE_RL_wr ;

  // rule RL_timeout
  assign CAN_FIRE_RL_timeout = busy ;
  assign WILL_FIRE_RL_timeout = busy ;

  // rule RL_rd_addr
  assign CAN_FIRE_RL_rd_addr = o_rd_addr_cdc_dEMPTY_N && !reading && !busy ;
  assign WILL_FIRE_RL_rd_addr = CAN_FIRE_RL_rd_addr && !WILL_FIRE_RL_wr ;

  // rule RL_errorTxn
  assign CAN_FIRE_RL_errorTxn = reset_req ;
  assign WILL_FIRE_RL_errorTxn = reset_req ;

  // rule RL_rd_data
  assign CAN_FIRE_RL_rd_data =
	     hbc_o_mem_ready && i_rd_data_cdc_sFULL_N &&
	     o_rd_addr_cdc_dEMPTY_N &&
	     reading ;
  assign WILL_FIRE_RL_rd_data =
	     CAN_FIRE_RL_rd_data && !WILL_FIRE_RL_errorTxn ;

  // inputs to muxes for submodule ports
  assign MUX_hbc_mem_addr_write_1__VAL_1 =
	     { 8'b0, o_wr_addr_cdc_dD_OUT[52:29] } ;
  assign MUX_hbc_mem_addr_write_1__VAL_2 =
	     { 8'b0, o_rd_addr_cdc_dD_OUT[52:29] } ;
  assign MUX_i_rd_data_cdc_enq_1__VAL_1 =
	     { o_rd_addr_cdc_dD_OUT[62:61], 67'h000000006F56E06F1 } ;
  assign MUX_i_rd_data_cdc_enq_1__VAL_2 =
	     { o_rd_addr_cdc_dD_OUT[62:61], hbc_o_mem_rdata, 3'd1 } ;

  // inlined wires
  assign pwTimeout_whas = busy && timeout_counter_Q_OUT == 10'd0 ;

  // register busy
  assign busy_D_IN = !WILL_FIRE_RL_rd_data && !WILL_FIRE_RL_errorTxn ;
  assign busy_EN =
	     WILL_FIRE_RL_rd_data || WILL_FIRE_RL_errorTxn ||
	     WILL_FIRE_RL_rd_addr ;

  // register reading
  assign reading_D_IN = !WILL_FIRE_RL_rd_data && !WILL_FIRE_RL_errorTxn ;
  assign reading_EN =
	     WILL_FIRE_RL_rd_data || WILL_FIRE_RL_errorTxn ||
	     WILL_FIRE_RL_rd_addr ;

  // submodule axi_data_f_rd_addr
  assign axi_data_f_rd_addr_D_IN =
	     { axi_arid,
	       axi_araddr,
	       axi_arlen,
	       axi_arsize,
	       axi_arburst,
	       axi_arlock,
	       axi_arcache,
	       axi_arprot,
	       axi_arqos,
	       axi_arregion } ;
  assign axi_data_f_rd_addr_ENQ = axi_arvalid && axi_data_f_rd_addr_FULL_N ;
  assign axi_data_f_rd_addr_DEQ = CAN_FIRE_RL_cdc3 ;
  assign axi_data_f_rd_addr_CLR = 1'b0 ;

  // submodule axi_data_f_rd_data
  assign axi_data_f_rd_data_D_IN = i_rd_data_cdc_dD_OUT ;
  assign axi_data_f_rd_data_ENQ = CAN_FIRE_RL_cdc5 ;
  assign axi_data_f_rd_data_DEQ = axi_rready && axi_data_f_rd_data_EMPTY_N ;
  assign axi_data_f_rd_data_CLR = 1'b0 ;

  // submodule axi_data_f_wr_addr
  assign axi_data_f_wr_addr_D_IN =
	     { axi_awid,
	       axi_awaddr,
	       axi_awlen,
	       axi_awsize,
	       axi_awburst,
	       axi_awlock,
	       axi_awcache,
	       axi_awprot,
	       axi_awqos,
	       axi_awregion } ;
  assign axi_data_f_wr_addr_ENQ = axi_awvalid && axi_data_f_wr_addr_FULL_N ;
  assign axi_data_f_wr_addr_DEQ = CAN_FIRE_RL_cdc1 ;
  assign axi_data_f_wr_addr_CLR = 1'b0 ;

  // submodule axi_data_f_wr_data
  assign axi_data_f_wr_data_D_IN = { axi_wdata, axi_wstrb, axi_wlast } ;
  assign axi_data_f_wr_data_ENQ = axi_wvalid && axi_data_f_wr_data_FULL_N ;
  assign axi_data_f_wr_data_DEQ = CAN_FIRE_RL_cdc2 ;
  assign axi_data_f_wr_data_CLR = 1'b0 ;

  // submodule axi_data_f_wr_resp
  assign axi_data_f_wr_resp_D_IN = i_wr_resp_cdc_dD_OUT ;
  assign axi_data_f_wr_resp_ENQ = CAN_FIRE_RL_cdc4 ;
  assign axi_data_f_wr_resp_DEQ = axi_bready && axi_data_f_wr_resp_EMPTY_N ;
  assign axi_data_f_wr_resp_CLR = 1'b0 ;

  // submodule hbc
  assign hbc_i_burst_length = cfg_i_burst_length ;
  assign hbc_i_burst_type = cfg_i_burst_type ;
  assign hbc_i_cfg_access = cfg_i_cfg_access ;
  assign hbc_i_dq = hb_out_in_i_dq ;
  assign hbc_i_initial_latency = cfg_i_initial_latency ;
  assign hbc_i_mem_addr =
	     WILL_FIRE_RL_wr ?
	       MUX_hbc_mem_addr_write_1__VAL_1 :
	       MUX_hbc_mem_addr_write_1__VAL_2 ;
  assign hbc_i_mem_wdata =
	     WILL_FIRE_RL_wr ? o_wr_data_cdc_dD_OUT[72:9] : 64'd0 ;
  assign hbc_i_mem_wstrb =
	     WILL_FIRE_RL_wr ? o_wr_data_cdc_dD_OUT[8:1] : 8'd0 ;
  assign hbc_i_rwds = hb_out_in_i_rwds ;
  assign hbc_i_txn_32_64 = cfg_i_txn_32_64 ;
  assign hbc_i_mem_valid = WILL_FIRE_RL_wr || WILL_FIRE_RL_rd_addr ;

  // submodule i_rd_data_cdc
  assign i_rd_data_cdc_sD_IN =
	     WILL_FIRE_RL_errorTxn ?
	       MUX_i_rd_data_cdc_enq_1__VAL_1 :
	       MUX_i_rd_data_cdc_enq_1__VAL_2 ;
  assign i_rd_data_cdc_sENQ = WILL_FIRE_RL_errorTxn || WILL_FIRE_RL_rd_data ;
  assign i_rd_data_cdc_dDEQ = CAN_FIRE_RL_cdc5 ;

  // submodule i_wr_resp_cdc
  assign i_wr_resp_cdc_sD_IN = { o_wr_addr_cdc_dD_OUT[62:61], 2'd0 } ;
  assign i_wr_resp_cdc_sENQ = CAN_FIRE_RL_wr ;
  assign i_wr_resp_cdc_dDEQ = CAN_FIRE_RL_cdc4 ;

  // submodule o_rd_addr_cdc
  assign o_rd_addr_cdc_sD_IN = axi_data_f_rd_addr_D_OUT ;
  assign o_rd_addr_cdc_sENQ = CAN_FIRE_RL_cdc3 ;
  assign o_rd_addr_cdc_dDEQ = WILL_FIRE_RL_rd_data || WILL_FIRE_RL_errorTxn ;

  // submodule o_wr_addr_cdc
  assign o_wr_addr_cdc_sD_IN = axi_data_f_wr_addr_D_OUT ;
  assign o_wr_addr_cdc_sENQ = CAN_FIRE_RL_cdc1 ;
  assign o_wr_addr_cdc_dDEQ = CAN_FIRE_RL_wr ;

  // submodule o_wr_data_cdc
  assign o_wr_data_cdc_sD_IN = axi_data_f_wr_data_D_OUT ;
  assign o_wr_data_cdc_sENQ = CAN_FIRE_RL_cdc2 ;
  assign o_wr_data_cdc_dDEQ = CAN_FIRE_RL_wr ;

  // submodule timeout_counter
  assign timeout_counter_DATA_A = 10'h0 ;
  assign timeout_counter_DATA_B = 10'd1023 ;
  assign timeout_counter_DATA_C = 10'd1023 ;
  assign timeout_counter_DATA_F = 10'h0 ;
  assign timeout_counter_ADDA = 1'b0 ;
  assign timeout_counter_ADDB = busy ;
  assign timeout_counter_SETC = WILL_FIRE_RL_rd_addr ;
  assign timeout_counter_SETF = 1'b0 ;

  // handling of inlined registers

  always@(posedge CLK_hb_clk or `BSV_RESET_EDGE RST_N_hb_rstn)
  if (RST_N_hb_rstn == `BSV_RESET_VALUE)
    begin
      busy <= `BSV_ASSIGNMENT_DELAY 1'd0;
      reading <= `BSV_ASSIGNMENT_DELAY 1'd0;
    end
  else
    begin
      if (busy_EN) busy <= `BSV_ASSIGNMENT_DELAY busy_D_IN;
      if (reading_EN) reading <= `BSV_ASSIGNMENT_DELAY reading_D_IN;
    end

  // synopsys translate_off
  `ifdef BSV_NO_INITIAL_BLOCKS
  `else // not BSV_NO_INITIAL_BLOCKS
  initial
  begin
    busy = 1'h0;
    reading = 1'h0;
  end
  `endif // BSV_NO_INITIAL_BLOCKS
  // synopsys translate_on
  assign debug_imem_valid=hbc.i_mem_valid;
  assign debug_omem_ready=hbc.i_mem_valid;
  assign debug_state=hbc.state;
  assign debug_counter = hbc.counter;
endmodule  // mkHB_Wrapper

